const today = new Date();
const startOfYear = new Date(today.getFullYear(), 0, 1);
const weekNum = Math.ceil((today - startOfYear) / 604800000);

const tofu_topics = [
  'tipos de hipoteca',
  'por qué el banco no siempre da la mejor oferta',
  'TIN vs TAE',
  'hipoteca fija vs variable',
  'cuánto necesitas ahorrado',
  'primera vivienda pasos'
];

const mofu_topics = [
  '5 errores antes de firmar',
  'cómo negociar',
  'qué mira el banco',
  'ratio endeudamiento',
  'broker vs banco solo',
  'documentación necesaria'
];

const bofu_topics = [
  'lo que hacemos en Firmax',
  'proceso del primer contacto a la firma',
  '25 años de experiencia',
  'analizamos tu caso'
];

const plan = [
  { id: 1, fase: 'TOFU', formato: 'Reel educativo 35-40 seg', tema: tofu_topics[weekNum % tofu_topics.length] },
  { id: 2, fase: 'TOFU', formato: 'Carrusel 6 slides', tema: tofu_topics[(weekNum + 1) % tofu_topics.length] },
  { id: 3, fase: 'TOFU', formato: 'Reel aspiracional 5-9 seg', tema: tofu_topics[(weekNum + 2) % tofu_topics.length] },
  { id: 4, fase: 'TOFU', formato: 'Story dato rápido', tema: tofu_topics[(weekNum + 3) % tofu_topics.length] },
  { id: 5, fase: 'MOFU', formato: 'Reel proceso 35-40 seg', tema: mofu_topics[weekNum % mofu_topics.length] },
  { id: 6, fase: 'MOFU', formato: 'Carrusel táctico 5 slides', tema: mofu_topics[(weekNum + 1) % mofu_topics.length] },
  { id: 7, fase: 'BOFU', formato: 'Spot publicitario 15-30 seg', tema: bofu_topics[weekNum % bofu_topics.length] }
];

return [{ json: { plan, weekNum, generatedAt: today.toISOString() } }];

const raw = $input.first().json.choices[0].message.content;
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    throw new Error('No se pudo parsear la respuesta de OpenAI: ' + raw.substring(0, 200));
  }
}

const piezas = parsed.piezas || [];
return piezas.map(p => ({ json: p }));

const items = $input.all();
const now = new Date().toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const emoji = { TOFU: '🔵', MOFU: '🟡', BOFU: '🔴' };

const headerMsg = {
  json: {
    isHeader: true,
    text: '📅 *PLAN DE CONTENIDO SEMANAL*
Mediterrane Firmax SL

' + now + '

*Total piezas:* ' + items.length + '
🔵 TOFU: 4 piezas
🟡 MOFU: 2 piezas
🔴 BOFU: 1 pieza

✅ *Todo guardado en Notion*

─────────────────────'
  }
};

const pieceMessages = items.map(item => {
  const p = item.json;
  const em = emoji[p.fase] || '⚪';
  let text = em + ' *PIEZA ' + p.id + ' — ' + p.fase + '*
';
  text += '📌 *Formato:* ' + p.formato + '
';
  text += '🎯 *Tema:* ' + p.tema + '

';
  text += '🎣 *HOOK*
' + p.hook + '

';
  text += '📝 *SCRIPT*
' + p.script + '

';
  text += '📣 *CTA*
' + p.cta + '

';
  text += '🎨 *PROMPT AVATAR*
' + p.prompt_avatar + '

';
  text += '📸 *CAPTION INSTAGRAM*
' + p.caption_instagram;
  if (p.disclaimer_legal && p.disclaimer_legal.length > 0) {
    text += '

⚖️ *DISCLAIMER LEGAL*
' + p.disclaimer_legal;
  }
  return { json: { isHeader: false, text: text, pieceId: p.id } };
});

return [headerMsg, ...pieceMessages];
